#include <bits/stdc++.h>
using namespace std;
int n,m,d[100005],ans[100005];
vector<int> g[100005];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=0;i<m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v),d[v]++;
    }
    queue<int> s,t;
    for(int i=1;i<=n;i++)
        if(!d[i])
            t.push(i),ans[i]=1;
    while(t.size()){
        s.push(t.front()),t.pop();
        int u=s.back(),len=g[u].size();
        for(int i=0;i<len;i++){
            if(!--d[g[u][i]])
                t.push(g[u][i]);
            ans[g[u][i]]=max(ans[g[u][i]],ans[u]+1);
        }
    }
    for(int i=1;i<=n;i++)
        printf("%d\n",ans[i]);
    return 0;
}
